// frontend/src/components/CheckoutModal.js
import React, { useState } from 'react';

const overlay = {
  position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.4)',
  display: 'flex', alignItems: 'center', justifyContent: 'center',
  zIndex: 1000, padding: '20px',
};
const box = {
  background: '#fff', borderRadius: '20px', padding: '28px',
  width: '100%', maxWidth: '360px',
  boxShadow: '0 8px 40px rgba(0,0,0,0.15)',
};

export default function CheckoutModal({ placeName, onSubmit, onClose }) {
  const [amount, setAmount] = useState('');
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (skipCost = false) => {
    setLoading(true);
    await onSubmit(skipCost ? null : amount ? parseFloat(amount) : null);
    setLoading(false);
  };

  return (
    <div style={overlay} onClick={e => e.target === e.currentTarget && onClose()}>
      <div style={box}>
        <div style={{ fontSize: '32px', textAlign: 'center', marginBottom: '8px' }}>💰</div>
        <div style={{ fontSize: '18px', fontWeight: '700', textAlign: 'center', color: '#1a1a2e', marginBottom: '6px' }}>
          Kitna Kharcha Hua?
        </div>
        <div style={{ fontSize: '13px', color: '#999', textAlign: 'center', marginBottom: '24px' }}>
          <strong style={{ color: '#1D9E75' }}>{placeName}</strong> mein aaj ka total bill
        </div>

        <div style={{ display: 'flex', alignItems: 'center', gap: '10px', marginBottom: '20px' }}>
          <span style={{ fontSize: '24px', fontWeight: '700', color: '#1D9E75' }}>₹</span>
          <input
            type="number"
            placeholder="0"
            value={amount}
            onChange={e => setAmount(e.target.value)}
            min="0"
            style={{
              flex: 1, border: '2px solid #e8e8e8', borderRadius: '12px',
              padding: '14px', fontSize: '22px', fontWeight: '600',
              color: '#1a1a2e', outline: 'none', textAlign: 'center',
            }}
            autoFocus
            onFocus={e => e.target.style.borderColor = '#1D9E75'}
            onBlur={e => e.target.style.borderColor = '#e8e8e8'}
          />
        </div>

        {/* Quick amount buttons */}
        <div style={{ display: 'flex', gap: '8px', marginBottom: '20px', flexWrap: 'wrap' }}>
          {[100, 250, 500, 1000].map(v => (
            <button
              key={v}
              onClick={() => setAmount(String(v))}
              style={{
                flex: 1, padding: '8px', background: amount == v ? '#1D9E75' : '#f4f4f4',
                color: amount == v ? '#fff' : '#555',
                border: 'none', borderRadius: '8px', fontSize: '13px',
                fontWeight: '500', cursor: 'pointer', minWidth: '60px',
              }}
            >₹{v}</button>
          ))}
        </div>

        <div style={{ fontSize: '12px', color: '#bbb', textAlign: 'center', marginBottom: '20px' }}>
          Aapka data anonymously use hoga doosron ki help ke liye 🙏
        </div>

        <div style={{ display: 'flex', gap: '10px' }}>
          <button
            onClick={() => handleSubmit(true)}
            disabled={loading}
            style={{
              flex: 1, padding: '13px', border: '1.5px solid #e8e8e8',
              background: '#fff', color: '#888', borderRadius: '12px',
              fontSize: '14px', cursor: 'pointer',
            }}
          >Skip</button>
          <button
            onClick={() => handleSubmit(false)}
            disabled={loading}
            style={{
              flex: 2, padding: '13px', background: '#1D9E75', color: '#fff',
              border: 'none', borderRadius: '12px', fontSize: '14px',
              fontWeight: '600', cursor: 'pointer',
            }}
          >{loading ? 'Saving...' : 'Submit Karo ✓'}</button>
        </div>
      </div>
    </div>
  );
}
